package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.internal.ConstructorConstructor;
import com.google.gson.internal.ObjectConstructor;
import com.google.gson.reflect.TypeToken;
import java.lang.reflect.Type;
import java.util.ArrayList;
import java.util.Collection;
import java.util.Collections;
import java.util.List;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

public class CollectionTypeAdapterFactoryTest {

  @Mock
  private ConstructorConstructor constructorConstructor;

  @Mock
  private Gson gson;

  @Mock
  private ObjectConstructor<Object> objectConstructor;

  @Mock
  private TypeAdapter<Object> elementTypeAdapter;

  private CollectionTypeAdapterFactory factory;

  @BeforeEach
  public void setUp() {
    MockitoAnnotations.openMocks(this);
    factory = new CollectionTypeAdapterFactory(constructorConstructor);
  }

  @Test
  public void create_returnsNullWhenRawTypeIsNotCollection() {
    TypeToken<String> typeToken = TypeToken.get(String.class);
    TypeAdapter<String> adapter = factory.create(gson, typeToken);
    assertNull(adapter);
  }

  @Test
  public void create_returnsAdapterWhenRawTypeIsCollection() {
    // Use ArrayList.class which is a Collection
    TypeToken<List<String>> typeToken = new TypeToken<List<String>>() {};
    Type elementType = $Gson$Types.getCollectionElementType(typeToken.getType(), typeToken.getRawType());

    when(gson.getAdapter(TypeToken.get(elementType))).thenReturn(elementTypeAdapter);
    when(constructorConstructor.get(typeToken)).thenReturn((ObjectConstructor) objectConstructor);

    TypeAdapter<List<String>> adapter = factory.create(gson, (TypeToken<List<String>>) typeToken);

    assertNotNull(adapter);
    // The returned adapter should be an instance of CollectionTypeAdapterFactory.Adapter
    assertEquals("com.google.gson.internal.bind.CollectionTypeAdapterFactory$Adapter", adapter.getClass().getName());
  }

  @Test
  public void create_worksWithCustomCollection() {
    class CustomCollection extends ArrayList<String> {}

    TypeToken<CustomCollection> typeToken = new TypeToken<CustomCollection>() {};
    Type elementType = $Gson$Types.getCollectionElementType(typeToken.getType(), typeToken.getRawType());

    when(gson.getAdapter(TypeToken.get(elementType))).thenReturn(elementTypeAdapter);
    when(constructorConstructor.get(typeToken)).thenReturn((ObjectConstructor) objectConstructor);

    TypeAdapter<CustomCollection> adapter = factory.create(gson, (TypeToken<CustomCollection>) typeToken);

    assertNotNull(adapter);
    assertEquals("com.google.gson.internal.bind.CollectionTypeAdapterFactory$Adapter", adapter.getClass().getName());
  }
}
